#!/bin/bash
echo "→ App installieren..."
echo '' | base64 -d | sudo tee /opt/charge-goertz/web/index.html > /dev/null
echo "  ✓ $(wc -c < /opt/charge-goertz/web/index.html) bytes"

echo "→ Flask API..."
echo '' | base64 -d | sudo tee /opt/charge-goertz/app.py > /dev/null
echo "  ✓ app.py"

sudo systemctl restart charge-goertz
sleep 2
systemctl is-active charge-goertz && echo "✓ Flask läuft!" || echo "❌ Fehler"
curl -s http://localhost:5000/api/status
echo ""
echo "✅ Fertig! Teste: http://192.168.3.103:8080"
